import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const bundlePath = resolve(__dirname, "../../core/dist/feedthrough.iife.js");
const outDir = resolve(__dirname, "../src/generated");
const outFile = resolve(outDir, "bundle.ts");

const iife = readFileSync(bundlePath, "utf-8");

mkdirSync(outDir, { recursive: true });
writeFileSync(
  outFile,
  `// AUTO-GENERATED by scripts/embed-bundle.mjs — do not edit\nexport const bridgeBundle = ${JSON.stringify(iife)};\n`,
);

console.log(`embedded ${iife.length} chars into src/generated/bundle.ts`);
